#include <bits/stdc++.h>
using namespace std;

const int N=3e6+6;

struct Node{
	int sum;
    Node *son[62];
}*root;

int t,n,q;
char s[N];

int cal(char c){
	if('0'<=c && c<='9')
		return 52+c-'0';
	if('a'<=c)
		return c-'a';
	return 26+c-'A';
}

int main(){
	scanf("%d",&t);
	while(t--){
		root=new Node;
		for(int i=0;i<62;i++)
			root->son[i]=NULL;
		root->sum=0;
		scanf("%d%d",&n,&q);
		for(int i=1;i<=n;i++){
			scanf("%s",s+1);
			int len=strlen(s+1);
			Node *p=root;
			for(int j=1;j<=len;j++){
				if(p->son[cal(s[j])]==NULL){
					Node *q=new Node;
					for(int k=0;k<62;k++)
						q->son[k]=NULL;
					q->sum=0;
					p->son[cal(s[j])]=q;
				}
				p=p->son[cal(s[j])];
				p->sum++;
			}
		}
		while(q--){
			scanf("%s",s+1);
			int len=strlen(s+1);
			Node *p=root;
			for(int j=1;j<=len;j++){
				p=p->son[cal(s[j])];
				if(p==NULL)
					break;
			}
			if(p!=NULL)
				printf("%d\n",p->sum);
			else
				puts("0");
		}
	}
	return 0;
}
